import { buildExamPathwayPath } from "@/lib/exam-pathways/build-exam-pathway-path";
import { getExamPathwayById } from "@/lib/exam-pathways/exam-product-registry";

import {
  NEW_GRAD_MINIMUM_CONTENT,
  NEW_GRAD_PUBLIC_SURFACE,
  expectedNewGradPremiumModuleKeys,
  listNewGradExamPathwaysFromRegistry,
  loadNewGradTransitionCatalog,
  newGradCatalogLessonCount,
} from "./new-grad-hub-program-model";

function yesNo(v: boolean): string {
  return v ? "Yes" : "No";
}

/**
 * Markdown report for `reports/` (generated by `scripts/write-new-grad-hub-report.mts`).
 * Uses only repo-local sources — no invented DB counts.
 */
export function buildNewGradHubProgramMarkdown(args: { generatedAtIso: string }): string {
  const pathways = listNewGradExamPathwaysFromRegistry();
  const keysOff = expectedNewGradPremiumModuleKeys(false, false);
  const keysOn = expectedNewGradPremiumModuleKeys(true, true);
  const catalog = loadNewGradTransitionCatalog();
  const { count: lessonCount } = newGradCatalogLessonCount();
  const metaQ = catalog?.meta?.totalQuestions;

  const lines: string[] = [];
  lines.push("# New Grad hub — inventory, minimums, and QA program");
  lines.push("");
  lines.push(`Generated: ${args.generatedAtIso}`);
  lines.push("");
  lines.push("## Part 1 — Pathway inventory (source: exam registry + navigation constants)");
  lines.push("");
  lines.push("| Public hub route | Pathway ID | Exam code | Exam key | Stripe tier |");
  lines.push("| --- | --- | --- | --- | --- |");
  for (const p of pathways) {
    lines.push(
      `| ${buildExamPathwayPath(p)} | ${p.id} | ${p.examCode} | ${p.examKey} | ${p.stripeTier} |`,
    );
  }
  lines.push(
    `| ${NEW_GRAD_PUBLIC_SURFACE.usMarketingHub} (marketing shell) | *(lessons/questions/CAT resolve to ${NEW_GRAD_PUBLIC_SURFACE.primaryPathwayId})* | — | — | — |`,
  );
  lines.push(
    `| ${NEW_GRAD_PUBLIC_SURFACE.canadaMarketingHub} (marketing shell) | *(CA mega-menu destinations use US transition pathway for CAT; lessons beside RN hub per region policy)* | — | — | — |`,
  );
  lines.push("");
  lines.push("### Premium module cards (transition hub, guest flags: scenarios off / OSCE off)");
  lines.push("");
  lines.push(`- **Study tools:** ${keysOff.studyTools.join(", ")}`);
  lines.push(`- **Readiness & progress:** ${keysOff.readiness.join(", ")}`);
  lines.push(`- **New graduate strip:** ${keysOff.newGradStrip.join(", ")}`);
  lines.push("");
  lines.push("When scenarios/OSCE public flags are **on**, locked state may change for: `clinical_cases` (NP only), `osce`. New Grad is **not** NP — `clinical_cases` never appears.");
  lines.push("");
  lines.push("### Gated vs public-safe modules");
  lines.push("");
  lines.push("- **Public marketing URLs:** transition lessons, questions, CAT landing, and new-grad strip cards with `wrapGuestWithLoginCallback: false` stay on marketing hosts.");
  lines.push("- **Subscriber app surfaces:** flashcards, practice exams, labs, med calc, weak areas, medication drills use `/login?callbackUrl=` for guests (no admin/staff hrefs).");
  lines.push("- **OSCE:** Tile remains visible for nursing pathways; when the public OSCE flag is off, `resolvePremiumCardHref` keeps locked navigation safe (`/` or login callback per card).");
  lines.push("");
  lines.push("### Counts from checked-in catalog (not live DB)");
  lines.push("");
  lines.push("| Metric | Value | Notes |");
  lines.push("| --- | ---: | --- |");
  lines.push(`| Lessons in \`new-grad-transition-catalog.json\` | ${lessonCount} | Minimum target ${NEW_GRAD_MINIMUM_CONTENT.lessons} |`);
  lines.push(
    `| Catalog meta \`totalQuestions\` | ${typeof metaQ === "number" ? metaQ : "—"} | Illustrative only; **live** flashcard/question/CAT pools come from Postgres + entitlement gates. Run \`cd nursenest-core && npx tsx scripts/write-new-grad-hub-report.mts\` with DATABASE_URL for optional Prisma augmentation (future). |`,
  );
  lines.push("");
  lines.push("### Topic coverage expectations (content program)");
  lines.push("");
  lines.push(
    "Transition-to-practice, prioritization/delegation, medication safety, clinical judgment, deterioration, shift scenarios, SBAR, documentation, safety/risk, infection control, scope, time management, therapeutic communication, basic labs, med math, skills refreshers, confidence/study plan.",
  );
  lines.push("");
  lines.push("### SEO / theme / leakage (engineering status)");
  lines.push("");
  const p = getExamPathwayById(NEW_GRAD_PUBLIC_SURFACE.primaryPathwayId);
  lines.push(`- **SEO:** Pathway \`seoTitle\` / \`seoDescription\` present on registry object: ${yesNo(Boolean(p?.seoTitle && p?.seoDescription))}.`);
  lines.push("- **Theme:** Hubs use `[data-theme]` + semantic tokens (`ExamPathwayHubPremiumModules` surfaces). E2E captures ocean + midnight + aurora where configured.");
  lines.push("- **Admin/staff leakage:** Forbidden on public hubs — verified in Playwright (`assertNoAdminLinks` / `assertNoForbiddenPublicLinks`).");
  lines.push("");
  lines.push("## Part 2 — Minimum content standards (targets vs catalog snapshot)");
  lines.push("");
  lines.push("| Dimension | Required minimum | Catalog / static snapshot | Meets minimum |");
  lines.push("| --- | ---: | ---: | --- |");
  const row = (label: string, min: number, cur: number | string) => {
    const c = typeof cur === "number" ? cur : 0;
    const ok = typeof cur === "number" ? cur >= min : false;
    return `| ${label} | ${min} | ${cur} | ${typeof cur === "number" ? (ok ? "Yes" : "**No — backlog**") : cur} |`;
  };
  lines.push(row("Public-facing lessons (catalog)", NEW_GRAD_MINIMUM_CONTENT.lessons, lessonCount));
  lines.push(
    `| Flashcards | ${NEW_GRAD_MINIMUM_CONTENT.flashcards} | *DB* | *Run pool diagnostics with DATABASE_URL* |`,
  );
  lines.push(
    `| Practice questions | ${NEW_GRAD_MINIMUM_CONTENT.practiceQuestions} | *DB* | *Run pool diagnostics with DATABASE_URL* |`,
  );
  lines.push(
    `| Prioritization / delegation / patient safety / NGN-style / labs / med calc / scenarios / comms — granular | see program doc | *DB / taxonomy export* | **TODO** — no fake counts in this report |`,
  );
  lines.push("");
  lines.push("## Part 3 — Implementation backlog (explicit)");
  lines.push("");
  lines.push("- **Lessons:** Expand `new-grad-transition-catalog.json` toward ≥60 transition lessons (batched imports per RN lesson library safety rules).");
  lines.push("- **Pools:** Align flashcards + exam_questions + CAT readiness floors with `NEW_GRAD_MINIMUM_CONTENT` using existing bank pipelines.");
  lines.push("- **Figma / visual cohesion:** New Grad uses the same `StudyCard` + semantic premium panels as RN hubs. Sync card hierarchy and spacing with the design system file used for marketing hubs (see `docs/ecosystem-design-system-convergence.md`); attach Figma frame links when the dedicated New Grad audit frame exists.");
  lines.push("");
  lines.push("## Part 4 — Playwright validation");
  lines.push("");
  lines.push("- Spec: `nursenest-core/tests/e2e/public/new-grad-hubs.spec.ts`");
  lines.push("- Command: `cd nursenest-core && npx playwright test tests/e2e/public/new-grad-hubs.spec.ts`");
  lines.push("- Screenshots: `nursenest-core/docs/screenshots/new-grad-e2e/`");
  lines.push("");
  lines.push("### Premium module keys when flags ON (reference)");
  lines.push("");
  lines.push(keysOn.studyTools.join(", "));
  lines.push("");
  return lines.join("\n");
}
